catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) {
        return;
    }

    var startDate = g_form.getValue('u_start_date');
    var endDate = g_form.getValue('u_end_date');

    if (!startDate || !endDate) {
        g_form.setValue('u_working_days', '');
        return;
    }

    var start = new Date(startDate);
    var end = new Date(endDate);

    if (end < start) {
        g_form.clearValue('u_working_days');
        g_form.showFieldMsg('u_end_date', 'End date cannot be earlier than start date.', 'error');
        return;
    }

    var workingDays = 0;
    var current = new Date(start);

    while (current <= end) {
        var day = current.getDay(); // 0 = Sunday, 6 = Saturday

        if (day !== 0 && day !== 6) {
            workingDays++;
        }

        current.setDate(current.getDate() + 1);
    }

    g_form.setValue('u_working_days', workingDays);
}
